mapper.select:
SELECT ROW_NUMBER() OVER (ORDER BY s.store_id) AS rn , s.co_id , s.store_id , s.store_type_cd , s.ste_id , s.store_name_ko , s.store_name_en , s.use_yn FROM fscps.bs_airstar_store s WHERE s.co_id = #{coId}
AND s.store_id ILIKE '%' || #{searchStoreId} || '%'
AND s.store_name_ko ILIKE '%' || #{searchStoreNm} || '%'
AND s.store_type_cd = #{searchStoreTypeCd}
ORDER BY s.store_id
